    if (token) headers.set("authorization", `Bearer ${token}`);
    const device = await buildDeviceInfo();
    if (!headers.has("x-extension-id")) headers.set("x-extension-id", config.allowedExtensionId || chrome.runtime.id);
    if (!headers.has("x-extension-context")) headers.set("x-extension-context", "browser-extension");
    if (!headers.has("x-install-id")) headers.set("x-install-id", device.install.installId);
    if (!headers.has("x-extension-version")) headers.set("x-extension-version", device.version);
    if (!headers.has("x-extension-device")) headers.set("x-extension-device", device.deviceLabel);

