    try {
      validation = await apiFetch("/api/session/validate", { method: "GET", skipProtection: true }, session.token);
    } catch (error) {
      if (shouldTryRefreshSession(error) && refreshSession && refreshSession.token) {
        return refreshSessionWithRefreshToken("validate-session-expired");
      }
      if (isTerminalSessionError(error)) await markSignedOutFromSessionError(error);
      throw error;
    }
