    let bootstrap = null;
    try {
      bootstrap = await apiFetch("/api/runtime/bootstrap", { method: "GET", skipProtection: true }, updatedSession.token);
    } catch {}
    const previousPolicy = normalizePolicy(storedPolicy || null);
    const policy = normalizePolicy({
      ...(validation.policy || {}),
      backendProfile: bootstrap && bootstrap.profile || null,
      ui: bootstrap && bootstrap.ui || null,
      runtimeProtection: bootstrap && bootstrap.runtimeProtection || null,
      runtimeStatic: bootstrap && bootstrap.runtimeStatic || previousPolicy.runtimeStatic || null,
      runtimeStaticUpdates: bootstrap && bootstrap.runtimeStaticUpdates || previousPolicy.runtimeStaticUpdates || null,
      minVersionOk: versionCompare(chrome.runtime.getManifest().version, validation.policy && validation.policy.minVersion || chrome.runtime.getManifest().version) >= 0,
      lastValidatedAt: new Date().toISOString(),
      user: validation.user || null
    });
