        const userMri = String(candidate && candidate.userMri || "").trim();
        const cid = bgRuntimePersonalCid({ cid: candidate && candidate.cid || "", accountTid: tid, accountOid: oid, homeAccountId, userMri, key: candidate && candidate.accountKey || "" });
        const personalIdentity = type === "personal" ? bgRuntimePersonalIdentityToken({ cid, accountTid: tid, accountOid: oid, homeAccountId, userMri, key: candidate && candidate.accountKey || "" }) : "";
