        const oauthSid = bgRuntimeOauthSid(candidate && (candidate.oauthSid || candidate.sid) || "");
        const canonicalAccountKey = bgMakeAccountKey(type, email, candidate && candidate.accountKey || identity, { accountTid: tid, accountOid: oid, homeAccountId, userMri, cid });
        const defaults = bgHeadlessTeamsDiscoveryDefaults(type);
        const rawPageUrl = String(candidate && candidate.pageUrl || defaults.pageUrl);
        const rawBaseUrl = String(candidate && candidate.baseUrl || defaults.baseUrl);
        const pageMismatch = bgNormalizeTeamsType(rawPageUrl) !== "unknown" && bgNormalizeTeamsType(rawPageUrl) !== type;
        const baseMismatch = bgNormalizeTeamsType(rawBaseUrl) !== "unknown" && bgNormalizeTeamsType(rawBaseUrl) !== type;
        const contextMismatch = pageMismatch || baseMismatch;
