            pageUrl: pageMismatch ? defaults.pageUrl : rawPageUrl,
            baseUrl: baseMismatch ? defaults.baseUrl : rawBaseUrl,
            endpointId: contextMismatch ? "" : candidate && candidate.endpointId || "",
            userMri: contextMismatch ? "" : userMri,
            tabId: contextMismatch ? -1 : Number.isFinite(Number(candidate && candidate.tabId)) ? Number(candidate.tabId) : -1,
            headers: contextMismatch ? null : candidate && candidate.headers || null,
            endpointBody: contextMismatch ? null : candidate && candidate.endpointBody || null,
            forceBody: contextMismatch ? null : candidate && candidate.forceBody || null,
            activityBody: contextMismatch ? null : candidate && candidate.activityBody || null
