                email: email || prior.email || "",
                accountOid: oid || prior.accountOid || "",
                accountTid: tid || prior.accountTid || "",
                homeAccountId: candidate && candidate.homeAccountId || prior.homeAccountId || "",
                oauthSid: oauthSid || prior.oauthSid || "",
                cid: cid || prior.cid || "",
                userMri: userMri || prior.userMri || "",
                displayName: bgPreferAccountDisplayName(candidate && candidate.displayName || "", prior.displayName || ""),
                accountKey: bgMakeAccountKey(type, email || prior.email || "", candidate && candidate.accountKey || prior.accountKey || identity, { accountTid: tid || prior.accountTid, accountOid: oid || prior.accountOid, homeAccountId: homeAccountId || prior.homeAccountId || "", userMri: userMri || prior.userMri || "", cid: cid || prior.cid || "" }),
                pageUrl: normalizedCandidate.pageUrl || prior.pageUrl || defaults.pageUrl,
