                    accountOid: token.accountOid || runtime.accountOid || runtime.oauthResolvedOid || "",
                    accountTid: token.accountTid || runtime.accountTid || runtime.oauthResolvedTid || "",
                    oauthSid: runtime.oauthSid || token.oauthSid || "",
                    known: true,
                    source: "headless-auth-cache"
