        if (globalThis.TeamsHelperInteractiveExtensionAuthInProgress === true) return { ok: false, skipped: true, reason: "extension-auth-in-progress" };
        if (!(await bgExtensionSessionReadyForTeams())) return { ok: false, skipped: true, reason: "extension-sign-in-required" };
