async function bgEnsureLicensedRuntimeActivation(reason = "post-auth-runtime") {
    const requestedReason = String(reason || "post-auth-runtime");
    const priority = value => /post-auth-login|beta|license-refresh/i.test(value) ? 4 : /teams-account-discovered|runtime-installed|runtime-startup/i.test(value) ? 3 : /service-worker-load|popup/i.test(value) ? 2 : 1;
    if (bgLicensedRuntimeActivationPromise) {
        if (!bgLicensedRuntimeActivationPendingReason || priority(requestedReason) >= priority(bgLicensedRuntimeActivationPendingReason)) bgLicensedRuntimeActivationPendingReason = requestedReason;
        return bgLicensedRuntimeActivationPromise
    }
    bgLicensedRuntimeActivationPromise = (async () => {
        let currentReason = requestedReason;
        let result = null;
        let passes = 0;
        while (currentReason && passes < 4) {
            bgLicensedRuntimeActivationCurrentReason = currentReason;
            bgLicensedRuntimeActivationPendingReason = "";
            result = await bgEnsureLicensedRuntimeActivationInternal(currentReason);
            passes += 1;
            const pending = String(bgLicensedRuntimeActivationPendingReason || "");
            currentReason = pending && pending !== bgLicensedRuntimeActivationCurrentReason ? pending : ""
        }
        return result
    })().finally(() => {
        bgLicensedRuntimeActivationPromise = null;
        bgLicensedRuntimeActivationCurrentReason = "";
        bgLicensedRuntimeActivationPendingReason = ""
    });
    return bgLicensedRuntimeActivationPromise
}

