  const parsed = typeof bgRuntimeIdentityFromKey === 'function' ? bgRuntimeIdentityFromKey(key) : {};
  const email = bgNormalizeAccountEmail(raw.targetAccountEmail || raw.teamsAccountEmail || raw.email || normalized.targetAccountEmail || normalized.teamsAccountEmail || bgAccountKeyEmail(key) || '');
  const tid = th37322BusinessGuid(raw.oauthResolvedTid || raw.accountTid || raw.tenantId || normalized.oauthResolvedTid || normalized.accountTid || parsed.accountTid || '');
  const oid = th37322BusinessGuid(raw.oauthResolvedOid || raw.accountOid || raw.oid || normalized.oauthResolvedOid || normalized.accountOid || parsed.accountOid || '');
  const homeAccountId = th216Text(raw.homeAccountId || normalized.homeAccountId || '').trim().toLowerCase();
  const homeTenant = th37322BusinessGuid(homeAccountId.includes('.') ? homeAccountId.slice(homeAccountId.lastIndexOf('.') + 1) : '');
