  if (!token) {
    try {
      token = await bgHeadlessTeamsAcquireTokenSilently(state, scope, reason, cached || null, recipe);
    } catch (error) {
      if (!th37322BusinessRefreshNeedsAuthorizeReseed(error)) throw error;
      token = await th37322AcquireBusinessTokenBySilentAuthorize(state, scope, reason, recipe, 'cached-refresh-family-rejected');
    }
  }
